import{_ as a,o as i,c as t,ak as e,an as r,ao as o,ap as s}from"./chunks/framework.24mNDJkT.js";const g=JSON.parse('{"title":"分层体系结构","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/初识计算机网络/分层体系结构.md","filePath":"计算机网络/初识计算机网络/分层体系结构.md","lastUpdated":1775045546000}'),n={name:"计算机网络/初识计算机网络/分层体系结构.md"};function h(d,l,p,c,b,u){return i(),t("div",null,[...l[0]||(l[0]=[e('<h1 id="分层体系结构" tabindex="-1">分层体系结构 <a class="header-anchor" href="#分层体系结构" aria-label="Permalink to “分层体系结构”">​</a></h1><h2 id="一、网络分层模型" tabindex="-1">一、网络分层模型 <a class="header-anchor" href="#一、网络分层模型" aria-label="Permalink to “一、网络分层模型”">​</a></h2><p><img src="'+r+'" alt="alt text"></p><h3 id="_1-osi-参考模型-7层" tabindex="-1">1. OSI 参考模型（7层） <a class="header-anchor" href="#_1-osi-参考模型-7层" aria-label="Permalink to “1. OSI 参考模型（7层）”">​</a></h3><blockquote><p><strong>理论标准（纸面标准）</strong></p></blockquote><p>从下到上共 7 层：</p><ol><li>物理层</li><li>数据链路层</li><li>网络层</li><li>运输层</li><li>会话层</li><li>表示层</li><li>应用层</li></ol><p>👉 特点：</p><ul><li>结构完整、定义清晰</li><li><strong>实际应用中使用较少</strong></li></ul><h3 id="_2-tcp-ip-参考模型-4层" tabindex="-1">2. TCP/IP 参考模型（4层） <a class="header-anchor" href="#_2-tcp-ip-参考模型-4层" aria-label="Permalink to “2. TCP/IP 参考模型（4层）”">​</a></h3><blockquote><p><strong>事实标准（实际使用）</strong></p></blockquote><table tabindex="0"><thead><tr><th>TCP/IP层</th><th>对应OSI层</th></tr></thead><tbody><tr><td>应用层</td><td>应用层 + 表示层 + 会话层</td></tr><tr><td>运输层</td><td>运输层</td></tr><tr><td>网际层</td><td>网络层</td></tr><tr><td>网络接口层</td><td>数据链路层 + 物理层</td></tr></tbody></table><p>👉 命名原因：</p><ul><li><strong>TCP</strong>：运输层核心协议</li><li><strong>IP</strong>：网际层核心协议（Internet Protocol）</li></ul><p>👉 特点：</p><ul><li>实际互联网使用标准</li><li>更加简化</li></ul><h3 id="_3-教学五层模型-重点" tabindex="-1">3. 教学五层模型（重点） <a class="header-anchor" href="#_3-教学五层模型-重点" aria-label="Permalink to “3. 教学五层模型（重点）”">​</a></h3><blockquote><p><strong>学习使用</strong></p></blockquote><ol><li>应用层</li><li>运输层</li><li>网络层</li><li>数据链路层</li><li>物理层</li></ol><p>👉 本课程基于此模型</p><h2 id="二、各层作用-核心理解" tabindex="-1">二、各层作用（核心理解） <a class="header-anchor" href="#二、各层作用-核心理解" aria-label="Permalink to “二、各层作用（核心理解）”">​</a></h2><h3 id="_1-应用层" tabindex="-1">1. 应用层 <a class="header-anchor" href="#_1-应用层" aria-label="Permalink to “1. 应用层”">​</a></h3><p>👉 <strong>解决：应用程序通信问题</strong></p><p>常见协议：</p><ul><li>HTTP（网页）</li><li>FTP（文件传输）</li><li>SMTP（邮件）</li></ul><p>👉 本质：</p><blockquote><p>面向用户应用</p></blockquote><h3 id="_2-运输层" tabindex="-1">2. 运输层 <a class="header-anchor" href="#_2-运输层" aria-label="Permalink to “2. 运输层”">​</a></h3><p>👉 <strong>解决：进程 ↔ 进程 通信（端到端）</strong></p><p>常见协议：</p><ul><li>TCP</li><li>UDP</li></ul><h3 id="_3-网络层" tabindex="-1">3. 网络层 <a class="header-anchor" href="#_3-网络层" aria-label="Permalink to “3. 网络层”">​</a></h3><p>👉 <strong>解决：主机 ↔ 主机通信 + 路由</strong></p><p>功能：</p><ul><li>IP 寻址</li><li>路由选择</li></ul><p>👉 通俗理解：</p><blockquote><p>数据如何跨网络，从一个主机到另一个主机</p></blockquote><h3 id="_4-数据链路层" tabindex="-1">4. 数据链路层 <a class="header-anchor" href="#_4-数据链路层" aria-label="Permalink to “4. 数据链路层”">​</a></h3><p>👉 <strong>解决：局域网内传输问题</strong></p><p>功能：</p><ul><li>帧封装</li><li>MAC 地址识别</li><li>差错检测</li></ul><p>👉 范围：</p><blockquote><p>一段链路 / 一个网络（局域网）</p></blockquote><h3 id="_5-物理层" tabindex="-1">5. 物理层 <a class="header-anchor" href="#_5-物理层" aria-label="Permalink to “5. 物理层”">​</a></h3><p>👉 <strong>解决：比特如何表示（0/1）</strong></p><p>例如：</p><ul><li>电信号</li><li>光信号</li><li>无线电波</li></ul><h2 id="三、数据封装过程-发送端" tabindex="-1">三、数据封装过程（发送端） <a class="header-anchor" href="#三、数据封装过程-发送端" aria-label="Permalink to “三、数据封装过程（发送端）”">​</a></h2><p><img src="'+o+'" alt="alt text"></p><h3 id="总体流程" tabindex="-1">总体流程 <a class="header-anchor" href="#总体流程" aria-label="Permalink to “总体流程”">​</a></h3><p>👉 <strong>从上到下逐层封装</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>应用层 → 运输层 → 网络层 → 数据链路层 → 物理层</span></span></code></pre></div><h3 id="数据单位变化" tabindex="-1">数据单位变化 <a class="header-anchor" href="#数据单位变化" aria-label="Permalink to “数据单位变化”">​</a></h3><table tabindex="0"><thead><tr><th>层</th><th>名称</th></tr></thead><tbody><tr><td>应用层</td><td>报文（Message）</td></tr><tr><td>运输层</td><td>段（Segment）</td></tr><tr><td>网络层</td><td>包（Packet）</td></tr><tr><td>数据链路层</td><td>帧（Frame）</td></tr><tr><td>物理层</td><td>比特流（Bit）</td></tr></tbody></table><h3 id="封装过程" tabindex="-1">封装过程 <a class="header-anchor" href="#封装过程" aria-label="Permalink to “封装过程”">​</a></h3><ol><li><p>应用层：添加应用层协议头</p></li><li><p>运输层：添加 TCP/UDP 头</p></li><li><p>网络层：添加 IP 头</p></li><li><p>数据链路层：</p><ul><li>添加头 + 尾（校验）</li></ul></li><li><p>物理层：</p><ul><li>转换为信号（电/光/无线）</li></ul></li></ol><p>👉 本质：</p><blockquote><p>一层一层“加壳”</p></blockquote><h2 id="四、数据解封过程-接收端" tabindex="-1">四、数据解封过程（接收端） <a class="header-anchor" href="#四、数据解封过程-接收端" aria-label="Permalink to “四、数据解封过程（接收端）”">​</a></h2><p><img src="'+s+'" alt="alt text"></p><h3 id="总体流程-1" tabindex="-1">总体流程 <a class="header-anchor" href="#总体流程-1" aria-label="Permalink to “总体流程”">​</a></h3><p>👉 <strong>从下到上逐层解封</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>物理层 → 数据链路层 → 网络层 → 运输层 → 应用层</span></span></code></pre></div><h3 id="解封过程" tabindex="-1">解封过程 <a class="header-anchor" href="#解封过程" aria-label="Permalink to “解封过程”">​</a></h3><ol><li><p><strong>物理层</strong></p><ul><li>信号 → 比特流</li><li>去掉物理层信息</li></ul></li><li><p><strong>数据链路层</strong></p><ul><li>校验数据（CRC）</li><li>判断 MAC 地址</li><li>去头去尾</li></ul></li><li><p><strong>网络层</strong></p><ul><li>判断 IP 地址</li><li>去掉 IP 头</li></ul></li><li><p><strong>运输层</strong></p><ul><li>解析端口号</li><li>分发给对应进程</li></ul></li><li><p><strong>应用层</strong></p><ul><li>按协议解析数据（如 HTTP）</li></ul></li></ol><h2 id="五、关键概念总结" tabindex="-1">五、关键概念总结 <a class="header-anchor" href="#五、关键概念总结" aria-label="Permalink to “五、关键概念总结”">​</a></h2><h3 id="_1-协议-protocol" tabindex="-1">1. 协议（Protocol） <a class="header-anchor" href="#_1-协议-protocol" aria-label="Permalink to “1. 协议（Protocol）”">​</a></h3><p>👉 本质：</p><blockquote><p>通信双方的“约定规则”</p></blockquote><p>作用：</p><ul><li>定义数据格式</li><li>定义通信流程</li></ul><h3 id="_2-分层思想" tabindex="-1">2. 分层思想 <a class="header-anchor" href="#_2-分层思想" aria-label="Permalink to “2. 分层思想”">​</a></h3><p>优点：</p><ul><li>降低复杂度</li><li>各层独立发展</li><li>易于维护与排错</li></ul><p>👉 类比：</p><blockquote><p>各司其职，互不干扰</p></blockquote><h3 id="_3-通信必须满足" tabindex="-1">3. 通信必须满足 <a class="header-anchor" href="#_3-通信必须满足" aria-label="Permalink to “3. 通信必须满足”">​</a></h3><p>👉 <strong>对等层协议必须一致</strong></p><p>否则：</p><ul><li>无法解析数据</li><li>通信失败</li></ul><h3 id="_4-数据包完整性原则-重点" tabindex="-1">4. 数据包完整性原则（重点） <a class="header-anchor" href="#_4-数据包完整性原则-重点" aria-label="Permalink to “4. 数据包完整性原则（重点）”">​</a></h3><p>👉 网络上传输的数据包：</p><p>✔ 可以没有上层 ❌ 不能没有下层</p><p>例如：</p><ul><li>可以没有应用层（如 ICMP）</li><li><strong>必须有链路层 + 物理层</strong></li></ul><p>👉 原因：</p><blockquote><p>没有下层就无法在网络上传输</p></blockquote><h3 id="_5-两个核心顺序-必记" tabindex="-1">5. 两个核心顺序（必记） <a class="header-anchor" href="#_5-两个核心顺序-必记" aria-label="Permalink to “5. 两个核心顺序（必记）”">​</a></h3><h4 id="发送端" tabindex="-1">发送端： <a class="header-anchor" href="#发送端" aria-label="Permalink to “发送端：”">​</a></h4><blockquote><p><strong>自上而下（封装）</strong></p></blockquote><h4 id="接收端" tabindex="-1">接收端： <a class="header-anchor" href="#接收端" aria-label="Permalink to “接收端：”">​</a></h4><blockquote><p><strong>自下而上（解封）</strong></p></blockquote><h2 id="六、核心一句话总结" tabindex="-1">六、核心一句话总结 <a class="header-anchor" href="#六、核心一句话总结" aria-label="Permalink to “六、核心一句话总结”">​</a></h2><p>👉 <strong>计算机网络本质：</strong></p><blockquote><p>数据在分层协议体系中 <strong>逐层封装 → 网络传输 → 逐层解封</strong></p></blockquote>',95)])])}const _=a(n,[["render",h]]);export{g as __pageData,_ as default};
